// src/commands/list.ts
async function listCommand(options) {
  const spinner = options.json ? null : ora({ text: "Fetching blips...", spinner: "dots" }).start();
  const result = await listBlips();
  if (result.error) {
    spinner?.fail(source_default.red(result.error));
    process.exit(1);
  }
  spinner?.stop();
  const blips = result.data.blips;
  if (options.json) {
    console.log(JSON.stringify(blips, null, 2));
    return;
  }
  renderBlipsTable(blips);
}

// src/commands/get.ts
async function getCommand(serial, options) {
  const spinner = options.json ? null : ora({ text: "Fetching blip...", spinner: "dots" }).start();
  const result = await getBlip(serial);
  if (result.error) {
    spinner?.fail(source_default.red(result.error));
    process.exit(1);
  }
  spinner?.stop();
  const blip = result.data.blip;
  if (options.json) {
    console.log(JSON.stringify(blip, null, 2));
    return;
  }
  renderBlipBox(blip);
}

// src/commands/edit.ts
import inquirer from "inquirer";
async function editCommand(serial, content) {
  if (!hasApiKey()) {
    renderErrorBox("API key not configured", "Run: blip config set key <your-key>");
    process.exit(1);
  }
  let finalContent = content || "";
  if (!finalContent.trim()) {
    const answers = await inquirer.prompt([
      {
        type: "editor",
        name: "content",
        message: "Edit blip:",
        validate: (input) => {
          if (!input.trim()) return "Content is required";
          if (input.length > 280) return "Content must be 280 characters or less";
          return true;
        }
      }
    ]);
    finalContent = answers.content;
  }
  if (finalContent.length > 280) {
    renderErrorBox("Content must be 280 characters or less");
    process.exit(1);
  }
  const spinner = ora({ text: "Updating blip...", spinner: "dots" }).start();
  const result = await updateBlip(serial, finalContent.trim());
  if (result.error) {
    spinner.fail(source_default.red(result.error));
    process.exit(1);
  }
  spinner.succeed(source_default.green(`Updated ${serial}`));
  const blip = result.data.blip;
  console.log();
  console.log(source_default.gray("   ") + source_default.cyan.bold(blip.blip_serial) + source_default.gray(" \u2502 ") + source_default.white(blip.content));
}

// src/commands/delete.ts
import inquirer2 from "inquirer";
async function deleteCommand(serial, options) {
  if (!hasApiKey()) {
    renderErrorBox("API key not configured", "Run: blip config set key <your-key>");
    process.exit(1);
  }
  if (!options.force) {
    const answers = await inquirer2.prompt([
      {
        type: "confirm",
        name: "confirm",
        message: `Delete blip ${source_default.cyan(serial)}?`,
        default: false
      }
    ]);
    if (!answers.confirm) {
      console.log(source_default.gray("Cancelled"));
      return;
    }
  }
  const spinner = ora({ text: "Deleting blip...", spinner: "dots" }).start();
  const result = await deleteBlip(serial);
  if (result.error) {
    spinner.fail(source_default.red(result.error));
    process.exit(1);
  }
  spinner.succeed(source_default.green(`Deleted ${serial}`));
}

// src/index.ts
var SERIAL_PATTERN = /^[a-zA-Z0-9]{1,6}$/;
var showHelp = process.argv.includes("--help") || process.argv.includes("-h");
var showVersion = process.argv.includes("--version") || process.argv.includes("-V");
var noArgs = process.argv.length <= 2;
if (showHelp || showVersion || noArgs) {
  showBanner();
}
var program2 = new Command();
program2.name("blip").description("CLI for managing blips").version("1.0.0");
program2.command("add <content...>").description("Create a new blip").alias("new").action(async (contentParts) => {
  if (!hasApiKey()) {
    renderErrorBox("API key not configured", "Run: blip config set key <your-key>");
    process.exit(1);
  }
  await newCommand(contentParts.join(" "));
});
program2.command("ls").description("List all blips").option("--json", "Output as JSON").action(async (options) => {
  await listCommand(options);
});
program2.command("rm <serial>").description("Delete a blip").option("-f, --force", "Skip confirmation").action(async (serial, options) => {
  await deleteCommand(serial, options);
});
program2.command("edit <serial> [content...]").description("Edit a blip").alias("e").action(async (serial, contentParts = []) => {
  await editCommand(serial, contentParts.join(" "));
});
program2.command("interactive").description("Interactive mode").alias("i").action(async () => {
  const { action } = await inquirer3.prompt([
    {
      type: "list",
      name: "action",
      message: "What would you like to do?",
      choices: [
        { name: "Create a new blip", value: "create" },
        { name: "View all blips", value: "list" },
        { name: "View a specific blip", value: "get" },
        { name: "Edit a blip", value: "edit" },
        { name: "Delete a blip", value: "delete" },
        { name: "Configure settings", value: "config" },
        new inquirer3.Separator(),
        { name: "Exit", value: "exit" }
      ]
    }
  ]);
  switch (action) {
    case "create": {
      if (!hasApiKey()) {
        renderErrorBox("API key not configured", "Run: blip config set key <your-key>");
        process.exit(1);
      }
      const { content } = await inquirer3.prompt([
        {
          type: "input",
          name: "content",
          message: "Blip content:",
          validate: (input) => {
            if (!input.trim()) return "Content is required";
            if (input.length > 280) return "Content must be 280 characters or less";
            return true;
          }
        }
      ]);
      await newCommand(content);
      break;
    }
    case "list":
      await listCommand({});
      break;
    case "get": {
      const { serial } = await inquirer3.prompt([
        {
          type: "input",
          name: "serial",
          message: "Blip serial:",
          validate: (input) => SERIAL_PATTERN.test(input) || "Invalid serial format"
        }
      ]);
      await getCommand(serial, {});
      break;
    }
    case "edit": {
      const { serial } = await inquirer3.prompt([
        {
          type: "input",
          name: "serial",
          message: "Blip serial to edit:",
          validate: (input) => SERIAL_PATTERN.test(input) || "Invalid serial format"
        }
      ]);
      await editCommand(serial);
      break;
    }
    case "delete": {
      const { serial } = await inquirer3.prompt([
        {
          type: "input",
          name: "serial",
          message: "Blip serial to delete:",
          validate: (input) => SERIAL_PATTERN.test(input) || "Invalid serial format"
        }
      ]);
      await deleteCommand(serial, {});
      break;
    }
    case "config": {
      const config2 = getConfig();
      renderConfigBox(config2);
      const { setting } = await inquirer3.prompt([
        {
          type: "list",
          name: "setting",
          message: "What would you like to configure?",
          choices: [
            { name: "Set API key", value: "key" },
            { name: "Set API URL", value: "url" },
            { name: "Back", value: "back" }
          ]
        }
      ]);
      if (setting !== "back") {
        const { value } = await inquirer3.prompt([
          {
            type: "input",
            name: "value",
            message: `Enter ${setting}:`,
            validate: (input) => input.trim().length > 0 || "Value is required"
          }
        ]);
        setConfig(setting, value);
        renderSuccessBox(`${setting} saved`);
      }
      break;
    }
    case "exit":
      console.log(source_default.gray("Bye!"));
      break;
  }
});
program2.command("config").description("Manage configuration").argument("[action]", "set or list").argument("[key]", "config key (key or url)").argument("[value]", "config value").action(async (action, key, value) => {
  if (!action || action === "list") {
    const config2 = getConfig();
    renderConfigBox(config2);
    return;
  }
  if (action === "set" && key && value) {
    if (key !== "key" && key !== "url") {
      renderErrorBox("Invalid config key", 'Use "key" or "url"');
      process.exit(1);
    }
    setConfig(key, value);
    renderSuccessBox(`${key} saved`);
    return;
  }
  renderErrorBox("Invalid usage", "blip config set <key|url> <value>\n       blip config list");
  process.exit(1);
});
async function handleDefaultCommand(args, jsonMode) {
  const arg = args.join(" ");
  if (args.length === 0) {
    await listCommand({ json: jsonMode });
    return;
  }
  if (args.length === 1 && SERIAL_PATTERN.test(args[0])) {
    await getCommand(args[0], { json: jsonMode });
    return;
  }
  if (!hasApiKey()) {
    renderErrorBox("API key not configured", "Run: blip config set key <your-key>");
    process.exit(1);
  }
  await newCommand(arg);
}
program2.argument("[args...]", "Serial to view, or content to create").option("--json", "Output as JSON (for list/get)").action(async (args, options) => {
  await handleDefaultCommand(args || [], options.json || false);
});
program2.parse(process.argv);
